'use strict';

// ============================================================
//  CONSTANTES GLOBAIS
// ============================================================
const TILE_SIZE  = 32;
const CANVAS_W   = 800;
const CANVAS_H   = 576;
const TILE_COLS  = Math.floor(CANVAS_W / TILE_SIZE);
const TILE_ROWS  = Math.floor(CANVAS_H / TILE_SIZE);

// Limite máximo de vida do jogador (16 = 8 corações)
const PLAYER_MAX_HP_CAP = 16;

// Zoom: quantos tiles cabem na tela muda com o scale
let GAME_SCALE = 1.5;
const SCALE_MIN = 1;
const SCALE_MAX = 3;
const SCALE_STEP = 0.5;

// Tiles visíveis e viewport — recalculados só quando GAME_SCALE muda
let _cachedScale = null;
let _visibleCols, _visibleRows, _viewW, _viewH;
function _rebuildScaleCache() {
  _cachedScale  = GAME_SCALE;
  _visibleCols  = Math.ceil(CANVAS_W / (TILE_SIZE * GAME_SCALE)) + 2;
  _visibleRows  = Math.ceil(CANVAS_H / (TILE_SIZE * GAME_SCALE)) + 2;
  _viewW        = CANVAS_W / GAME_SCALE;
  _viewH        = CANVAS_H / GAME_SCALE;
}
_rebuildScaleCache();
function visibleCols() { if(GAME_SCALE!==_cachedScale) _rebuildScaleCache(); return _visibleCols; }
function visibleRows() { if(GAME_SCALE!==_cachedScale) _rebuildScaleCache(); return _visibleRows; }
function viewW()       { if(GAME_SCALE!==_cachedScale) _rebuildScaleCache(); return _viewW; }
function viewH()       { if(GAME_SCALE!==_cachedScale) _rebuildScaleCache(); return _viewH; }

// Indicadores de borda do mapa — posições e rotações fixas, calculadas uma vez
const EDGE_INDICATORS = [
  {dir:'north', x:CANVAS_W/2,    y:10,           rot:0},
  {dir:'south', x:CANVAS_W/2,    y:CANVAS_H-10,  rot:Math.PI},
  {dir:'east',  x:CANVAS_W-10,   y:CANVAS_H/2,   rot:Math.PI/2},
  {dir:'west',  x:10,            y:CANVAS_H/2,   rot:-Math.PI/2},
];
