class NPC {
  constructor(def, tx, ty) {
    this.def   = def;
    this.tx    = tx;
    this.ty    = ty;
    this.x     = tx * TILE_SIZE + TILE_SIZE / 2;
    this.y     = ty * TILE_SIZE + TILE_SIZE / 2;
    this.alive = true;
    this.floatT = Math.random() * Math.PI * 2;
    // Direção de idle (alterna lentamente)
    this.idleDir   = ['south','south','east','west'][Math.floor(Math.random()*4)];
    this._idleTimer = 2 + Math.random() * 3;
    this._bobT      = 0;
  }
 
  get cx() { return this.x; }
  get cy() { return this.y; }
 
  isNearPlayer(player) {
    const dx = Math.abs(player.cx - this.cx);
    const dy = Math.abs(player.cy - this.cy);
    return dx < TILE_SIZE * 1.3 && dy < TILE_SIZE * 1.3;
  }
 
  update(dt) {
    this.floatT += dt;
    this._bobT  += dt;
    this._idleTimer -= dt;
    if (this._idleTimer <= 0) {
      const dirs = ['south','east','west','south','south'];
      this.idleDir = dirs[Math.floor(Math.random() * dirs.length)];
      this._idleTimer = 2.5 + Math.random() * 3;
    }
  }
 
  draw(ctx, camera) {
    const { sx, sy } = camera.worldToScreen(this.x - TILE_SIZE / 2, this.y - TILE_SIZE / 2);
    if (sx > CANVAS_W + 64 || sx < -64 || sy > CANVAS_H + 64 || sy < -64) return;
 
    const d   = this.def;
    const bob = Math.sin(this._bobT * 1.8) * 1.2;
 
    // Sombra
    ctx.fillStyle = 'rgba(0,0,0,0.28)';
    ctx.beginPath();
    ctx.ellipse(sx + 10, sy + 21, 8, 4, 0, 0, Math.PI * 2);
    ctx.fill();
 
    // Botas
    ctx.fillStyle = '#5a3010';
    ctx.fillRect(sx + 4,  sy + 17 + bob, 5, 5);
    ctx.fillRect(sx + 11, sy + 17 + bob, 5, 5);
 
    // Calças/meias
    ctx.fillStyle = '#c8c0a0';
    ctx.fillRect(sx + 5,  sy + 14 + bob, 4, 4);
    ctx.fillRect(sx + 11, sy + 14 + bob, 4, 4);
 
    // Robe / roupa (corpo)
    ctx.fillStyle = d.robeColor;
    ctx.fillRect(sx + 3, sy + 8 + bob, 14, 9);
 
    // Detalhe da roupa
    ctx.fillStyle = d.robeAccent;
    ctx.fillRect(sx + 3, sy + 8 + bob, 14, 3);
 
    // Braços (pele)
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 1, sy + 9 + bob, 3, 6);
    ctx.fillRect(sx + 16,sy + 9 + bob, 3, 6);
 
    // Rosto
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 5, sy + 3 + bob, 10, 7);
 
    // Cabelo / chapéu (depende do NPC)
    ctx.fillStyle = d.hairColor;
    ctx.fillRect(sx + 4, sy + 2 + bob, 12, 3);
    // Lateral do cabelo
    ctx.fillRect(sx + 4, sy + 3 + bob, 2, 5);
    ctx.fillRect(sx + 14,sy + 3 + bob, 2, 5);
 
    // Olhos (por direção)
    const ed = { north:{ex:0,ey:-4}, south:{ex:0,ey:0}, east:{ex:1,ey:-1}, west:{ex:-1,ey:-1} }[this.idleDir] ?? {ex:0,ey:0};
    ctx.fillStyle = d.eyeColor;
    ctx.fillRect(sx + 7  + ed.ex, sy + 5 + ed.ey + bob, 2, 2);
    ctx.fillRect(sx + 11 + ed.ex, sy + 5 + ed.ey + bob, 2, 2);
 
    // Nome flutuante acima
    ctx.save();
    ctx.font = '6px "Press Start 2P"';
    ctx.textAlign = 'center';
    const nameY = sy - 6 + Math.sin(this.floatT * 1.5) * 1.5;
    ctx.fillStyle = 'rgba(0,0,0,0.55)';
    ctx.fillRect(sx + 10 - ctx.measureText(d.name).width / 2 - 3, nameY - 8, ctx.measureText(d.name).width + 6, 11);
    ctx.fillStyle = '#f0e8a0';
    ctx.fillText(d.name, sx + 10, nameY);
    ctx.textAlign = 'left';
    ctx.restore();
  }
 
  // Tooltip [X] (chamado pelo Player se estiver perto)
  drawTooltip(ctx, camera) {
    const { sx, sy } = camera.worldToScreen(this.x - TILE_SIZE / 2, this.y - TILE_SIZE / 2);
    const bob = Math.sin(Date.now() * 0.005) * 2;
    ctx.save();
    ctx.fillStyle = 'rgba(0,0,0,0.75)';
    ctx.beginPath();
    ctx.roundRect(sx + 3, sy - 26 + bob, 21, 12, 3);
    ctx.fill();
    ctx.fillStyle = '#a0e0ff';
    ctx.font = TOOLTIP_FONT;
    ctx.textAlign = 'center';
    ctx.fillText('[X]', sx + 13, sy - 16 + bob);
    ctx.textAlign = 'left';
    ctx.restore();
  }
}

