// ── QuestGiver: NPC exclusivo para missões ───────────────────
class QuestGiver {
  constructor(def, tx, ty) {
    this.def    = def;
    this.tx     = tx;
    this.ty     = ty;
    this.x      = tx * TILE_SIZE + TILE_SIZE / 2;
    this.y      = ty * TILE_SIZE + TILE_SIZE / 2;
    this.floatT  = Math.random() * Math.PI * 2;
    this._bobT   = 0;
    this.idleDir = 'south';
    this._idleTimer = 2 + Math.random() * 3;
  }

  get cx() { return this.x; }
  get cy() { return this.y; }

  isNearPlayer(player) {
    return Math.abs(player.cx - this.cx) < TILE_SIZE * 1.3 &&
           Math.abs(player.cy - this.cy) < TILE_SIZE * 1.3;
  }

  update(dt) {
    this.floatT += dt;
    this._bobT  += dt;
    this._idleTimer -= dt;
    if (this._idleTimer <= 0) {
      const dirs = ['south', 'east', 'west', 'south'];
      this.idleDir = dirs[Math.floor(Math.random() * dirs.length)];
      this._idleTimer = 2.5 + Math.random() * 3;
    }
  }

  // Determina o estado do ícone acima da cabeça baseado no QuestSystem
  _questState(questSystem) {
    for (const qid of this.def.quests) {
      const prog = questSystem.progress[qid];
      if (!prog) continue;
      if (prog.status === 'ready') return 'ready';   // pode entregar
    }
    // Tem missão disponível (não iniciada ou ativa)?
    for (const qid of this.def.quests) {
      const prog = questSystem.progress[qid];
      if (!prog || prog.status === 'active') return 'available';
    }
    return 'done'; // todas completas
  }

  draw(ctx, camera, questSystem) {
    const { sx, sy } = camera.worldToScreen(this.x - TILE_SIZE / 2, this.y - TILE_SIZE / 2);
    if (sx > CANVAS_W + 64 || sx < -64 || sy > CANVAS_H + 64 || sy < -64) return;

    const d   = this.def;
    const bob = Math.sin(this._bobT * 1.8) * 1.2;

    // Sombra
    ctx.fillStyle = 'rgba(0,0,0,0.28)';
    ctx.beginPath();
    ctx.ellipse(sx + 10, sy + 21, 8, 4, 0, 0, Math.PI * 2);
    ctx.fill();

    // Botas
    ctx.fillStyle = '#3a2008';
    ctx.fillRect(sx + 4,  sy + 17 + bob, 5, 5);
    ctx.fillRect(sx + 11, sy + 17 + bob, 5, 5);

    // Calças
    ctx.fillStyle = '#c8c0a0';
    ctx.fillRect(sx + 5,  sy + 14 + bob, 4, 4);
    ctx.fillRect(sx + 11, sy + 14 + bob, 4, 4);

    // Robe
    ctx.fillStyle = d.robeColor;
    ctx.fillRect(sx + 3, sy + 8 + bob, 14, 9);
    ctx.fillStyle = d.robeAccent;
    ctx.fillRect(sx + 3, sy + 8 + bob, 14, 3);

    // Braços
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 1,  sy + 9 + bob, 3, 6);
    ctx.fillRect(sx + 16, sy + 9 + bob, 3, 6);

    // Rosto
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 5, sy + 3 + bob, 10, 7);

    // Cabelo
    ctx.fillStyle = d.hairColor;
    ctx.fillRect(sx + 4, sy + 2 + bob, 12, 3);
    ctx.fillRect(sx + 4, sy + 3 + bob, 2, 5);
    ctx.fillRect(sx + 14,sy + 3 + bob, 2, 5);

    // Olhos
    const ed = { north:{ex:0,ey:-4}, south:{ex:0,ey:0}, east:{ex:1,ey:-1}, west:{ex:-1,ey:-1} }[this.idleDir] ?? {ex:0,ey:0};
    ctx.fillStyle = d.eyeColor;
    ctx.fillRect(sx + 7  + ed.ex, sy + 5 + ed.ey + bob, 2, 2);
    ctx.fillRect(sx + 11 + ed.ex, sy + 5 + ed.ey + bob, 2, 2);

    // ── Ícone ! ou ✓ flutuante ───────────────────────────────
    if (questSystem) {
      const state = this._questState(questSystem);
      const iconY = sy - 16 + Math.sin(this.floatT * 2.2) * 2.5;
      if (state === 'ready') {
        // ✓ — missão pronta para entregar (brilha)
        ctx.fillStyle = '#00ff80';
        ctx.font = '11px "Press Start 2P"';
        ctx.textAlign = 'center';
        ctx.fillText('✓', sx + 10, iconY);
      } else if (state === 'available') {
        // ! — missão disponível
        ctx.fillStyle = d.badgeColor;
        ctx.font = '12px "Press Start 2P"';
        ctx.textAlign = 'center';
        ctx.fillText('!', sx + 10, iconY);
      }
      ctx.textAlign = 'left';
    }

    // Nome flutuante
    ctx.save();
    ctx.font = '6px "Press Start 2P"';
    ctx.textAlign = 'center';
    const nameY = sy - 6 + Math.sin(this.floatT * 1.5) * 1.5;
    ctx.fillStyle = 'rgba(0,0,0,0.55)';
    ctx.fillRect(sx + 10 - ctx.measureText(d.name).width / 2 - 3, nameY - 8, ctx.measureText(d.name).width + 6, 11);
    ctx.fillStyle = '#ffd080';
    ctx.fillText(d.name, sx + 10, nameY);
    ctx.textAlign = 'left';
    ctx.restore();
  }

  drawTooltip(ctx, camera) {
    const { sx, sy } = camera.worldToScreen(this.x - TILE_SIZE / 2, this.y - TILE_SIZE / 2);
    const bob = Math.sin(Date.now() * 0.005) * 2;
    ctx.save();
    ctx.fillStyle = 'rgba(0,0,0,0.75)';
    ctx.beginPath(); ctx.roundRect(sx + 3, sy - 26 + bob, 21, 12, 3); ctx.fill();
    ctx.fillStyle = '#ffd080';
    ctx.font = TOOLTIP_FONT;
    ctx.textAlign = 'center';
    ctx.fillText('[X]', sx + 13, sy - 16 + bob);
    ctx.textAlign = 'left';
    ctx.restore();
  }
}

// ── QuestSystem ──────────────────────────────────────────────
// progress[questId] = { status: 'active'|'ready'|'done', count: N }
class QuestSystem {
  constructor(ctx) {
    this.ctx      = ctx;
    this.active   = false;   // tela de log aberta?
    this.alpha    = 0;
    this.progress = {};      // estado de todas as missões
    this._sel     = 0;       // item selecionado no log
    this._scroll  = 0;
    this._W = 560; this._H = 460;
    this._X = (CANVAS_W - this._W) / 2;
    this._Y = (CANVAS_H - this._H) / 2;

    // Notificação de missão nova / completa
    this._notif      = 0;
    this._notifText  = '';
    this._notifColor = '#60ffa0';
  }

  // Inicia ou retoma interação com um QuestGiver — retorna diálogo e estado
  interact(giverDef) {
    // Coleta missões disponíveis e prontas para entregar
    const ready   = giverDef.quests.filter(qid => this.progress[qid]?.status === 'ready');
    const active  = giverDef.quests.filter(qid => this.progress[qid]?.status === 'active');
    const pending = giverDef.quests.filter(qid => !this.progress[qid]);

    // 1. Entregar missão pronta (primeira encontrada)
    if (ready.length > 0) {
      return { action: 'deliver', questId: ready[0] };
    }
    // 2. Oferecer nova missão
    if (pending.length > 0) {
      return { action: 'offer', questId: pending[0] };
    }
    // 3. Missão em progresso
    if (active.length > 0) {
      return { action: 'progress', questId: active[0] };
    }
    return { action: 'none' };
  }

  // Aceita uma missão
  accept(questId) {
    if (this.progress[questId]) return;
    this.progress[questId] = { status: 'active', count: 0 };
    this._notify(`Missão aceita: ${QUEST_DEFS[questId].title}`, '#f0c040');
  }

  // Registra evento de progresso
  onKill(enemyType) {
    for (const [qid, def] of Object.entries(QUEST_DEFS)) {
      if (def.type !== 'kill' || def.target !== enemyType) continue;
      const prog = this.progress[qid];
      if (!prog || prog.status !== 'active') continue;
      prog.count = Math.min(def.required, prog.count + 1);
      if (prog.count >= def.required) {
        prog.status = 'ready';
        this._notify(`Missão completa: ${def.title}! Fale com ${QUEST_GIVER_DEFS[def.giver].name}`, '#60ffa0');
      }
    }
  }

  onCollect(itemType, amount = 1) {
    for (const [qid, def] of Object.entries(QUEST_DEFS)) {
      if (def.type !== 'collect' || def.target !== itemType) continue;
      const prog = this.progress[qid];
      if (!prog || prog.status !== 'active') continue;
      prog.count = Math.min(def.required, prog.count + amount);
      if (prog.count >= def.required) {
        prog.status = 'ready';
        this._notify(`Missão completa: ${def.title}! Fale com ${QUEST_GIVER_DEFS[def.giver].name}`, '#60ffa0');
      }
    }
  }

  onExplore(mapId) {
    for (const [qid, def] of Object.entries(QUEST_DEFS)) {
      if (def.type !== 'explore' || def.target !== mapId) continue;
      const prog = this.progress[qid];
      if (!prog || prog.status !== 'active') continue;
      prog.count = 1;
      prog.status = 'ready';
      this._notify(`Missão completa: ${def.title}! Fale com ${QUEST_GIVER_DEFS[def.giver].name}`, '#60ffa0');
    }
  }

  // Entrega a missão e dá recompensa ao jogador
  deliver(questId, player, spawnItemFn) {
    const prog = this.progress[questId];
    if (!prog || prog.status !== 'ready') return null;
    prog.status = 'done';
    const def = QUEST_DEFS[questId];
    if (def.reward.gems)  player.gems += def.reward.gems;
    if (def.reward.item) {
      const itemDef = SHOP_ITEMS.find(it => it.id === def.reward.item);
      if (itemDef) {
        const existing = !itemDef.equipSlot && player.inventory.find(e => e.id === itemDef.id);
        if (existing) existing.qty = (existing.qty ?? 1) + 1;
        else player.inventory.push({ ...itemDef, qty: 1 });
      }
    }
    return def.reward;
  }

  _notify(text, color) {
    this._notifText  = text;
    this._notifColor = color;
    this._notif      = 3.5;
  }

  openLog() { this.active = true; this.alpha = 0; }
  closeLog() { this.active = false; }

  update(dt, input) {
    if (this._notif > 0) this._notif -= dt;
    if (!this.active) return;
    if (this.alpha < 1) this.alpha = Math.min(1, this.alpha + dt * 7);

    const allIds = Object.keys(QUEST_DEFS);
    const n = allIds.length;
    if (input.isJust('KeyL') || input.isJust('Escape')) { this.closeLog(); return; }
    if (input.isJust('ArrowUp')   || input.isJust('KeyK')) this._sel = (this._sel - 1 + n) % n;
    if (input.isJust('ArrowDown') || input.isJust('KeyJ')) this._sel = (this._sel + 1) % n;
  }

  drawLog() {
    if (!this.active) return;
    const ctx = this.ctx;
    const { _X: BX, _Y: BY, _W: BW, _H: BH } = this;

    const HEADER_H = 50;
    const FOOTER_H = 28;
    const LIST_Y   = BY + HEADER_H;
    const LIST_H   = BH - HEADER_H - FOOTER_H;
    const CARD_H   = 80;
    const GAP_Y    = 6;
    const STEP     = CARD_H + GAP_Y;
    const allIds   = Object.keys(QUEST_DEFS);
    const n        = allIds.length;
    const VISIBLE  = Math.floor(LIST_H / STEP);
    const scrollStart = Math.max(0, Math.min(this._sel - Math.floor(VISIBLE / 2), Math.max(0, n - VISIBLE)));

    ctx.save();
    ctx.globalAlpha = this.alpha;

    // Overlay
    ctx.fillStyle = 'rgba(0,0,0,0.78)';
    ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

    // Painel
    const grad = ctx.createLinearGradient(BX, BY, BX, BY + BH);
    grad.addColorStop(0,    '#0e0a04');
    grad.addColorStop(0.08, '#0a0804');
    grad.addColorStop(0.92, '#0a0804');
    grad.addColorStop(1,    '#0e0a04');
    ctx.fillStyle = grad;
    ctx.beginPath(); ctx.roundRect(BX, BY, BW, BH, 6); ctx.fill();
    ctx.strokeStyle = '#c0a020'; ctx.lineWidth = 2;
    ctx.beginPath(); ctx.roundRect(BX+1, BY+1, BW-2, BH-2, 5); ctx.stroke();
    ctx.strokeStyle = '#2a1a04'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.roundRect(BX+4, BY+4, BW-8, BH-8, 3); ctx.stroke();

    // Título
    ctx.font = '14px "Press Start 2P"'; ctx.fillStyle = '#f0c040'; ctx.textAlign = 'center';
    ctx.fillText('MISSÕES', CANVAS_W / 2, BY + 30);
    ctx.strokeStyle = '#3a2a04'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(BX+16, BY+40); ctx.lineTo(BX+BW-16, BY+40); ctx.stroke();

    // Contadores
    const done   = Object.values(this.progress).filter(p => p.status === 'done').length;
    const total  = Object.keys(QUEST_DEFS).length;
    ctx.font = '9px "Press Start 2P"'; ctx.fillStyle = '#a08030'; ctx.textAlign = 'right';
    ctx.fillText(`${done}/${total} completas`, BX + BW - 16, BY + 30);
    ctx.textAlign = 'left';

    // ── Lista com clipping ───────────────────────────────────
    ctx.save();
    ctx.beginPath(); ctx.rect(BX + 8, LIST_Y, BW - 16, LIST_H); ctx.clip();

    for (let i = scrollStart; i < Math.min(n, scrollStart + VISIBLE); i++) {
      const qid  = allIds[i];
      const def  = QUEST_DEFS[qid];
      const prog = this.progress[qid];
      const status = prog?.status ?? 'locked';
      const isSel  = i === this._sel;

      const cx = BX + 16;
      const cy = LIST_Y + (i - scrollStart) * STEP + 4;
      const CW = BW - 32;

      // Cores por status
      const statusColors = {
        active:  { bg: 'rgba(20,16,4,0.9)',  border: '#c0a020', text: '#f0c040' },
        ready:   { bg: 'rgba(4,24,8,0.9)',   border: '#40ff80', text: '#60ffa0' },
        done:    { bg: 'rgba(8,8,8,0.6)',    border: '#303020', text: '#606040' },
        locked:  { bg: 'rgba(6,6,6,0.5)',    border: '#1a1a10', text: '#404030' },
      };
      const sc = statusColors[status] ?? statusColors.locked;

      // Card background
      ctx.fillStyle = isSel && status !== 'done'
        ? (status === 'ready' ? 'rgba(10,40,16,0.95)' : 'rgba(30,22,6,0.95)')
        : sc.bg;
      ctx.beginPath(); ctx.roundRect(cx, cy, CW, CARD_H, 5); ctx.fill();
      ctx.strokeStyle = isSel ? (status === 'ready' ? '#80ff80' : '#f0c040') : sc.border;
      ctx.lineWidth = isSel ? 2 : 1;
      ctx.beginPath(); ctx.roundRect(cx, cy, CW, CARD_H, 5); ctx.stroke();

      // Badge de status
      const badges = {
        active: { label: 'ATIVA',     color: '#f0c040', bg: 'rgba(60,40,0,0.8)' },
        ready:  { label: 'ENTREGAR',  color: '#40ff80', bg: 'rgba(0,60,20,0.8)' },
        done:   { label: 'CONCLUÍDA', color: '#606040', bg: 'rgba(20,20,10,0.8)' },
        locked: { label: 'DISPONÍVEL',color: '#808060', bg: 'rgba(20,20,10,0.6)' },
      };
      const badge = badges[status] ?? badges.locked;
      ctx.font = '9px "Press Start 2P"';
      const bw = ctx.measureText(badge.label).width + 8;
      ctx.fillStyle = badge.bg;
      ctx.beginPath(); ctx.roundRect(cx + CW - bw - 8, cy + 8, bw, 14, 3); ctx.fill();
      ctx.fillStyle = badge.color;
      ctx.textAlign = 'center';
      ctx.fillText(badge.label, cx + CW - bw / 2 - 8, cy + 20);
      ctx.textAlign = 'left';

      // Título
      ctx.font = '10px "Press Start 2P"';
      ctx.fillStyle = status === 'done' ? '#504838' : sc.text;
      ctx.fillText(def.title, cx + 12, cy + 20);

      // Separador
      ctx.strokeStyle = sc.border + '44'; ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(cx + 8, cy + 27); ctx.lineTo(cx + CW - 8, cy + 27); ctx.stroke();

      // Descrição
      ctx.font = '9px "Press Start 2P"';
      ctx.fillStyle = status === 'done' ? '#3a3428' : '#8a7a50';
      ctx.fillText(def.desc, cx + 12, cy + 40);

      // Progresso (só para missões kill/collect ativas ou prontas)
      if (prog && (def.type === 'kill' || def.type === 'collect') && status !== 'done') {
        const count = prog.count ?? 0;
        const barW  = CW - 24;
        const barX  = cx + 12;
        const barY  = cy + 46;
        ctx.fillStyle = 'rgba(0,0,0,0.5)';
        ctx.fillRect(barX, barY, barW, 10);
        const fillW = barW * Math.min(1, count / def.required);
        ctx.fillStyle = status === 'ready' ? '#40ff80' : '#c0a020';
        ctx.fillRect(barX, barY, fillW, 10);
        ctx.strokeStyle = sc.border + '66'; ctx.lineWidth = 1;
        ctx.strokeRect(barX, barY, barW, 10);
        ctx.font = '8px "Press Start 2P"'; ctx.fillStyle = '#c0a040'; ctx.textAlign = 'right';
        ctx.fillText(`${count}/${def.required}`, cx + CW - 12, cy + 56);
        ctx.textAlign = 'left';
      } else if (def.type === 'explore' && prog && status !== 'done') {
        ctx.font = '8px "Press Start 2P"'; ctx.fillStyle = '#8a7a50';
        ctx.fillText(status === 'ready' ? '✓ Mapa explorado' : 'Explore o mapa alvo', cx + 12, cy + 55);
      }

      // Recompensa
      ctx.font = '8px "Press Start 2P"';
      ctx.fillStyle = status === 'done' ? '#404030' : '#a08030';
      ctx.fillText(`Recompensa: ${def.rewardDesc}`, cx + 12, cy + CARD_H - 10);
    }

    ctx.restore(); // encerra clip

    // Scrollbar
    if (n > VISIBLE) {
      const TX = BX + BW - 10, TY = LIST_Y + 4, TH = LIST_H - 8;
      const thumbH = Math.max(20, TH * (VISIBLE / n));
      const thumbY = TY + (scrollStart / Math.max(1, n - VISIBLE)) * (TH - thumbH);
      ctx.fillStyle = 'rgba(255,255,255,0.04)';
      ctx.beginPath(); ctx.roundRect(TX, TY, 5, TH, 3); ctx.fill();
      ctx.fillStyle = '#6a4a10';
      ctx.beginPath(); ctx.roundRect(TX, thumbY, 5, thumbH, 3); ctx.fill();
      ctx.fillStyle = '#c0a020'; ctx.font = '7px "Press Start 2P"'; ctx.textAlign = 'center';
      if (scrollStart > 0)           ctx.fillText('▲', TX + 2, LIST_Y - 2);
      if (scrollStart + VISIBLE < n) ctx.fillText('▼', TX + 2, LIST_Y + LIST_H + 10);
      ctx.textAlign = 'left';
    }

    // Footer
    ctx.font = '9px "Press Start 2P"'; ctx.fillStyle = '#4a3a10'; ctx.textAlign = 'center';
    ctx.fillText('[↑↓] NAVEGAR   [L/ESC] FECHAR', CANVAS_W / 2, BY + BH - 10);
    ctx.textAlign = 'left';

    ctx.restore();
  }

  // Notificação flutuante no centro da tela (missão aceita/completa)
  drawNotif() {
    if (this._notif <= 0) return;
    const a = Math.min(1, this._notif) * Math.min(1, (3.5 - this._notif) * 4);
    const ctx = this.ctx;
    ctx.save();
    ctx.globalAlpha = Math.max(0, a);
    ctx.font = '10px "Press Start 2P"'; ctx.textAlign = 'center';
    const tw = ctx.measureText(this._notifText).width;
    ctx.fillStyle = 'rgba(0,0,0,0.85)';
    ctx.beginPath(); ctx.roundRect(CANVAS_W/2 - tw/2 - 10, CANVAS_H * 0.72 - 17, tw + 20, 24, 4); ctx.fill();
    ctx.fillStyle = this._notifColor;
    ctx.fillText(this._notifText, CANVAS_W / 2, CANVAS_H * 0.72);
    ctx.textAlign = 'left';
    ctx.restore();
  }
}

// ============================================================
//  MERCADORES  (sistema independente dos NPCs)
//  Para adicionar um novo mercador, crie uma entrada em
//  MERCHANT_DEFS e coloque { id, tx, ty } em map.merchants[].
// ============================================================
const MERCHANT_DEFS = {
  'zelara': {
    id:         'zelara',
    name:       'Zelara',
    // Visual: alquimista com capuz roxo e capa escura
    skinColor:  '#a8c888',   // pele esverdeada (élfica)
    hoodColor:  '#3a1a6a',   // capuz roxo escuro
    hoodAccent: '#5a2a9a',
    capeColor:  '#1e1030',
    eyeColor:   '#c040e0',   // olhos roxos brilhantes
    gemColor:   '#e060ff',   // gema no broche
    greeting:   'Meus itens não têm preço... mas têm um preço.',
  },
  // Para adicionar novos mercadores, crie uma entrada aqui
  // e coloque { id, tx, ty } em map.merchants[].
};

class Merchant {
  constructor(def, tx, ty) {
    this.def    = def;
    this.tx     = tx;
    this.ty     = ty;
    this.x      = tx * TILE_SIZE + TILE_SIZE / 2;
    this.y      = ty * TILE_SIZE + TILE_SIZE / 2;
    this.alive  = true;
    this.floatT = Math.random() * Math.PI * 2;
    this._bobT  = 0;
    // Idle: alterna devagar entre olhar para frente e para o lado
    this._idleDir   = 'south';
    this._idleTimer = 3 + Math.random() * 3;
  }

  get cx() { return this.x; }
  get cy() { return this.y; }

  isNearPlayer(player) {
    return Math.abs(player.cx - this.cx) < TILE_SIZE * 1.3 &&
           Math.abs(player.cy - this.cy) < TILE_SIZE * 1.3;
  }

  update(dt) {
    this.floatT += dt;
    this._bobT  += dt;
    this._idleTimer -= dt;
    if (this._idleTimer <= 0) {
      const dirs = ['south', 'south', 'east', 'west'];
      this._idleDir   = dirs[Math.floor(Math.random() * dirs.length)];
      this._idleTimer = 2.5 + Math.random() * 3;
    }
  }

  draw(ctx, camera) {
    const { sx, sy } = camera.worldToScreen(this.x - TILE_SIZE / 2, this.y - TILE_SIZE / 2);
    if (sx > CANVAS_W + 64 || sx < -64 || sy > CANVAS_H + 64 || sy < -64) return;

    const d   = this.def;
    const bob = Math.sin(this._bobT * 1.5) * 1;
    const glowT = (Math.sin(this.floatT * 3.0) + 1) / 2; // 0..1 pulsante

    // Sombra com leve tint roxo
    ctx.fillStyle = 'rgba(80,0,120,0.22)';
    ctx.beginPath();
    ctx.ellipse(sx + 10, sy + 21, 9, 4, 0, 0, Math.PI * 2);
    ctx.fill();

    // Capa traseira (larga, escura)
    ctx.fillStyle = d.capeColor;
    ctx.fillRect(sx + 1, sy + 6 + bob, 18, 15);

    // Botas élficas (pontudas)
    ctx.fillStyle = '#1a0828';
    ctx.fillRect(sx + 3,  sy + 17 + bob, 5, 5);
    ctx.fillRect(sx + 12, sy + 17 + bob, 5, 5);
    // Ponta da bota
    ctx.fillRect(sx + 2,  sy + 20 + bob, 2, 2);
    ctx.fillRect(sx + 17, sy + 20 + bob, 2, 2);

    // Roupa interna (veste)
    ctx.fillStyle = d.hoodAccent;
    ctx.fillRect(sx + 4, sy + 8 + bob, 12, 10);

    // Broche central com gema pulsante
    ctx.fillStyle = d.gemColor;
    ctx.globalAlpha = 0.5 + glowT * 0.5;
    ctx.fillRect(sx + 8, sy + 10 + bob, 4, 4);
    ctx.globalAlpha = 1;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(sx + 9, sy + 11 + bob, 1, 1); // brilho

    // Braços com capa
    ctx.fillStyle = d.hoodColor;
    ctx.fillRect(sx + 0, sy + 8 + bob, 4, 9);
    ctx.fillRect(sx + 16, sy + 8 + bob, 4, 9);
    // Mãos (pele esverdeada)
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 1, sy + 15 + bob, 3, 3);
    ctx.fillRect(sx + 16, sy + 15 + bob, 3, 3);

    // Rosto
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 5, sy + 4 + bob, 10, 6);

    // Capuz — parte traseira
    ctx.fillStyle = d.hoodColor;
    ctx.fillRect(sx + 3, sy - 1 + bob, 14, 10);
    // Capuz — borda frontal (mais clara)
    ctx.fillStyle = d.hoodAccent;
    ctx.fillRect(sx + 4, sy + 0 + bob, 2, 8);
    ctx.fillRect(sx + 14, sy + 0 + bob, 2, 8);
    ctx.fillRect(sx + 4, sy + 0 + bob, 12, 2);
    // Orelhas élfica pontudas
    ctx.fillStyle = d.skinColor;
    ctx.fillRect(sx + 3, sy + 5 + bob, 2, 2);
    ctx.fillRect(sx + 3, sy + 4 + bob, 1, 1);  // ponta
    ctx.fillRect(sx + 15, sy + 5 + bob, 2, 2);
    ctx.fillRect(sx + 16, sy + 4 + bob, 1, 1); // ponta

    // Olhos roxos (por direção)
    const ed = {
      north: { ex: 0, ey: -2 },
      south: { ex: 0, ey:  0 },
      east:  { ex: 1, ey: -1 },
      west:  { ex:-1, ey: -1 },
    }[this._idleDir] ?? { ex: 0, ey: 0 };
    // Brilho dos olhos pulsante
    ctx.globalAlpha = 0.6 + glowT * 0.4;
    ctx.fillStyle = d.eyeColor;
    ctx.fillRect(sx + 7  + ed.ex, sy + 6 + ed.ey + bob, 2, 2);
    ctx.fillRect(sx + 11 + ed.ex, sy + 6 + ed.ey + bob, 2, 2);
    ctx.globalAlpha = 1;

    // Partícula mágica flutuante ao lado (simples, baseado em tempo)
    const px1 = Math.sin(this.floatT * 2.1) * 8;
    const py1 = Math.cos(this.floatT * 1.7) * 5;
    ctx.globalAlpha = 0.4 + glowT * 0.5;
    ctx.fillStyle = d.gemColor;
    ctx.fillRect(sx + 10 + px1, sy + 10 + py1 + bob, 2, 2);
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(sx + 10 + px1, sy + 10 + py1 + bob, 1, 1);
    ctx.globalAlpha = 1;

    // Nome flutuante com fundo roxo
    ctx.save();
    ctx.font = '6px "Press Start 2P"';
    ctx.textAlign = 'center';
    const nameY = sy - 8 + Math.sin(this.floatT * 1.4) * 1.5;
    const nameW = ctx.measureText(d.name).width;
    ctx.fillStyle = 'rgba(30,10,60,0.82)';
    ctx.fillRect(sx + 10 - nameW / 2 - 3, nameY - 8, nameW + 6, 11);
    ctx.strokeStyle = '#8040c0';
    ctx.lineWidth = 1;
    ctx.strokeRect(sx + 10 - nameW / 2 - 3, nameY - 8, nameW + 6, 11);
    ctx.fillStyle = '#d080ff';
    ctx.fillText(d.name, sx + 10, nameY);

    ctx.textAlign = 'left';
    ctx.restore();
  }

  drawTooltip(ctx, camera) {
    const { sx, sy } = camera.worldToScreen(this.x - TILE_SIZE / 2, this.y - TILE_SIZE / 2);
    const bob = Math.sin(Date.now() * 0.005) * 2;
    const label = '[X] Loja';
    const boxW  = 50;
    ctx.save();
    ctx.fillStyle = 'rgba(30,10,60,0.9)';
    ctx.beginPath(); ctx.roundRect(sx + 3, sy - 26 + bob, boxW, 12, 3); ctx.fill();
    ctx.strokeStyle = '#8040c0'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.roundRect(sx + 3, sy - 26 + bob, boxW, 12, 3); ctx.stroke();
    ctx.fillStyle = '#d080ff';
    ctx.font = TOOLTIP_FONT;
    ctx.textAlign = 'center';
    ctx.fillText(label, sx + 3 + boxW / 2, sy - 16 + bob);
    ctx.textAlign = 'left';
    ctx.restore();
  }
}

