      ctx.beginPath(); ctx.ellipse(x+10, y+13, 9, 7, 0, 0, Math.PI*2); ctx.fill();
      ctx.fillStyle = '#80e080';
      ctx.beginPath(); ctx.ellipse(x+7, y+10, 2.5, 2, 0, 0, Math.PI*2); ctx.fill();
      ctx.fillStyle = '#0a300a';
      ctx.beginPath(); ctx.arc(x+8, y+12, 1, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(x+12, y+12, 1, 0, Math.PI*2); ctx.fill();
