      ctx.fillStyle = '#0a200a';
      ctx.beginPath(); ctx.arc(x+8, y+13.5, 1, 0, Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(x+12, y+13.5, 1, 0, Math.PI*2); ctx.fill();
